// Delete uploaded file endpoint
app.delete('/api/upload/:filename', (req, res) => {
  const user = getUserFromRequest(req);
  const { filename } = req.params;

  // Sanitize filename to prevent directory traversal
  const sanitizedFilename = path.basename(filename);

  // Search for file in all upload directories
  const possiblePaths = [
    path.join(uploadDir, sanitizedFilename),
    path.join(avatarDir, sanitizedFilename),
    path.join(documentDir, sanitizedFilename)
  ];

  let fileFound = false;

  for (const filePath of possiblePaths) {
    if (fs.existsSync(filePath)) {
      fs.unlinkSync(filePath);
      fileFound = true;

      // Also try to delete thumbnail
      const thumbnailPath = path.join(thumbnailDir, `thumb-${sanitizedFilename}`);
      if (fs.existsSync(thumbnailPath)) {
        fs.unlinkSync(thumbnailPath);
      }

      break;
    }
  }

  if (!fileFound) {
    return res.status(404).json({ success: false, error: 'File not found' });
  }

  res.status(200).json({
    success: true,
    message: 'File deleted successfully',
    deletedBy: user.id
  });
});

// Get file info endpoint
app.get('/api/upload/info/:filename', (req, res) => {
  const { filename } = req.params;
  const sanitizedFilename = path.basename(filename);

  const directories = {
    uploads: uploadDir,
    avatars: avatarDir,
    documents: documentDir
  };

  for (const [dirName, dirPath] of Object.entries(directories)) {
    const filePath = path.join(dirPath, sanitizedFilename);
    if (fs.existsSync(filePath)) {
      const stats = fs.statSync(filePath);
      const ext = path.extname(sanitizedFilename).toLowerCase();

      const thumbnailPath = path.join(thumbnailDir, `thumb-${sanitizedFilename}`);
      const hasThumbnail = fs.existsSync(thumbnailPath);

      return res.status(200).json({
        success: true,
        data: {
          filename: sanitizedFilename,
          directory: dirName,
          size: stats.size,
          extension: ext,
          path: `/public/uploads/${dirName === 'uploads' ? '' : dirName + '/'}${sanitizedFilename}`,
          thumbnail: hasThumbnail ? `/public/uploads/thumbnails/thumb-${sanitizedFilename}` : null,
          createdAt: stats.birthtime,
          modifiedAt: stats.mtime
        }
      });
    }
  }

  res.status(404).json({ success: false, error: 'File not found' });
});

